package parser

func Parse(raw string) Config {
	if raw == "" {
		panic("empty config")
	}
	return Config{}
}

type Config struct{}

package parser

import "errors"

func Parse(raw string) (Config, error) {
	if raw == "" {
		return Config{}, errors.New("empty config")
	}
	return Config{}, nil
}

type Config struct{}
